// src/lab/meta/runner.rs

use super::mutation::Mutation;
use crate::lab::{LabRuntime, LabConfig, OracleMode};
use crate::lab::oracle::{Oracle, Violation};
use crate::cx::Cx;
use std::time::Duration;

/// Result of running a mutation test
#[derive(Debug)]
pub struct MutationResult {
    pub mutation: Mutation,
    pub violations_found: Vec<Violation>,
    pub expected_oracles: Vec<Oracle>,
    pub triggered_oracles: Vec<Oracle>,
    pub passed: bool,
    pub execution_trace: Vec<TraceEvent>,
    pub error_message: Option<String>,
    pub execution_time: Duration,
}

impl MutationResult {
    pub fn oracle_triggered(&self, oracle: Oracle) -> bool {
        self.triggered_oracles.contains(&oracle)
    }

    pub fn all_expected_triggered(&self) -> bool {
        self.expected_oracles.iter().all(|o| self.triggered_oracles.contains(o))
    }

    pub fn any_expected_triggered(&self) -> bool {
        self.expected_oracles.iter().any(|o| self.triggered_oracles.contains(o))
    }
}

/// Configuration for mutation testing
#[derive(Clone)]
pub struct MutationConfig {
    /// Timeout for each mutation test
    pub timeout: Duration,

    /// Whether to capture full trace
    pub capture_trace: bool,

    /// Entropy seed for deterministic mutations
    pub seed: u64,

    /// Whether to continue after first failure
    pub fail_fast: bool,

    /// Verbosity level for logging
    pub verbosity: Verbosity,
}

#[derive(Clone, Copy, PartialEq, Eq)]
pub enum Verbosity {
    Quiet,
    Normal,
    Verbose,
    Trace,
}

impl Default for MutationConfig {
    fn default() -> Self {
        Self {
            timeout: Duration::from_secs(5),
            capture_trace: true,
            seed: 0xMETA_TEST_SEED,
            fail_fast: false,
            verbosity: Verbosity::Normal,
        }
    }
}

/// Run a single mutation test
pub fn run_mutation_test(mutation: Mutation, config: &MutationConfig) -> MutationResult {
    let start = std::time::Instant::now();

    tracing::info!(mutation = ?mutation, "Starting mutation test");

    let lab_config = LabConfig {
        entropy_seed: config.seed,
        oracle_mode: OracleMode::Strict,
        mutation_injection: Some(mutation),
        timeout: Some(config.timeout),
        ..Default::default()
    };

    let mut runtime = LabRuntime::with_config(lab_config);
    let trace_buffer = if config.capture_trace {
        Some(TraceBuffer::new())
    } else {
        None
    };

    if let Some(ref buf) = trace_buffer {
        runtime.set_trace_sink(buf.handle());
    }

    // Run the mutation scenario
    let violations = runtime.run_with_timeout(config.timeout, || {
        execute_mutation_scenario(mutation, &mut runtime)
    });

    let elapsed = start.elapsed();

    let triggered_oracles: Vec<Oracle> = violations.iter()
        .map(|v| v.oracle)
        .collect::<std::collections::HashSet<_>>()
        .into_iter()
        .collect();

    let expected_oracles = mutation.expected_oracles();
    let passed = expected_oracles.iter().any(|o| triggered_oracles.contains(o));

    tracing::info!(
        mutation = ?mutation,
        passed = passed,
        expected = ?expected_oracles,
        triggered = ?triggered_oracles,
        elapsed_ms = elapsed.as_millis(),
        "Mutation test complete"
    );

    MutationResult {
        mutation,
        violations_found: violations,
        expected_oracles,
        triggered_oracles,
        passed,
        execution_trace: trace_buffer.map(|b| b.drain()).unwrap_or_default(),
        error_message: if passed { None } else {
            Some(format!(
                "Expected one of {:?} but only triggered {:?}",
                expected_oracles, triggered_oracles
            ))
        },
        execution_time: elapsed,
    }
}

/// Execute the scenario that demonstrates the mutation
fn execute_mutation_scenario(mutation: Mutation, runtime: &mut LabRuntime) {
    use Mutation::*;

    match mutation {
        // =====================================================================
        // Task Lifecycle Mutations
        // =====================================================================

        LeakTask => {
            runtime.block_on(async {
                let cx = runtime.root_cx();
                cx.region(|sub| async move {
                    // Spawn task but never await it
                    let _handle = sub.spawn(async move |cx: Cx| {
                        // Infinite loop - task never completes
                        loop {
                            cx.yield_now().await;
                        }
                    });
                    // Region closes, task still running -> TaskLeak
                }).await;
            });
        }

        OrphanTask => {
            runtime.block_on(async {
                let cx = runtime.root_cx();

                // Create a task handle that outlives its region
                let escaped_handle = cx.region(|sub| async move {
                    let handle = sub.spawn(async move |_| 42);
                    handle // Escape the handle
                }).await;

                // Try to use handle after region closed -> RegionTree/TaskLeak
                let _ = escaped_handle.await;
            });
        }

        DoubleComplete => {
            runtime.block_on(async {
                let cx = runtime.root_cx();
                cx.region(|sub| async move {
                    let handle = sub.spawn(async move |_| 42);
                    let _ = handle.await;

                    // Try to complete again (internal mutation - simulated)
                    runtime.inject_double_complete(handle.task_id());
                }).await;
            });
        }

        UnhandledTaskPanic => {
            runtime.block_on(async {
                let cx = runtime.root_cx();
                cx.region(|sub| async move {
                    sub.spawn(async move |_| {
                        panic!("Unhandled panic in task");
                    });
                    // Don't await - let panic propagate incorrectly
                }).await;
            });
        }

        // =====================================================================
        // Obligation Mutations
        // =====================================================================

        LeakObligation => {
            runtime.block_on(async {
                let cx = runtime.root_cx();
                let (tx, _rx) = cx.channel::<i32>(1);

                // Reserve send permit but never commit or abort
                let permit = tx.reserve(&cx).await.unwrap();
                drop(permit); // Drops without resolution -> ObligationLeak
            });
        }

        DoubleCommit => {
            runtime.block_on(async {
                let cx = runtime.root_cx();
                let (tx, rx) = cx.channel::<i32>(1);

                let permit = tx.reserve(&cx).await.unwrap();
                permit.commit(42);

                // Simulate double commit via internal mutation
                runtime.inject_double_commit(permit.obligation_id());
            });
        }

        DoubleAbort => {
            runtime.block_on(async {
                let cx = runtime.root_cx();
                let (tx, _rx) = cx.channel::<i32>(1);

                let permit = tx.reserve(&cx).await.unwrap();
                permit.abort();

                // Simulate double abort
                runtime.inject_double_abort(permit.obligation_id());
            });
        }

        CommitAfterAbort => {
            runtime.block_on(async {
                let cx = runtime.root_cx();
                let (tx, _rx) = cx.channel::<i32>(1);

                let permit = tx.reserve(&cx).await.unwrap();
                let oid = permit.obligation_id();
                permit.abort();

                // Try to commit after abort
                runtime.inject_commit_after_abort(oid);
            });
        }

        AbortAfterCommit => {
            runtime.block_on(async {
                let cx = runtime.root_cx();
                let (tx, rx) = cx.channel::<i32>(1);

                let permit = tx.reserve(&cx).await.unwrap();
                let oid = permit.obligation_id();
                permit.commit(42);

                // Try to abort after commit
                runtime.inject_abort_after_commit(oid);
            });
        }

        // =====================================================================
        // Cancellation Mutations
        // =====================================================================

        IgnoreCancel => {
            runtime.block_on(async {
                let cx = runtime.root_cx();

                cx.region(|sub| async move {
                    let handle = sub.spawn(async move |cx: Cx| {
                        // Ignore cancel signal - never check checkpoint
                        loop {
                            std::hint::black_box(0); // Busy loop, no checkpoint
                        }
                    });

                    // Request cancellation
                    handle.cancel();

                    // Task should drain but doesn't -> CancellationProtocol
                }).await;
            });
        }

        SkipDrain => {
            runtime.block_on(async {
                let cx = runtime.root_cx();

                // Configure runtime to skip drain phase (mutation mode)
                runtime.set_mutation_skip_drain(true);

                cx.region(|sub| async move {
                    let h1 = sub.spawn(async move |cx: Cx| {
                        cx.sleep(Duration::from_secs(100)).await;
                        42
                    });

                    // Cancel the task
                    sub.sleep(Duration::from_millis(10)).await;
                    h1.cancel();

                    // Region closes without draining -> CancellationProtocol
                }).await;
            });
        }

        SkipFinalize => {
            runtime.block_on(async {
                let cx = runtime.root_cx();

                runtime.set_mutation_skip_finalize(true);

                cx.region(|sub| async move {
                    sub.register_finalizer(|| {
                        // Finalizer should run but won't
                    });
                }).await;
            });
        }

        DrainBudgetExceeded => {
            runtime.block_on(async {
                let cx = runtime.root_cx();

                // Set very small drain budget
                runtime.set_drain_budget(Budget::new(1));

                cx.region(|sub| async move {
                    let h = sub.spawn(async move |cx: Cx| {
                        // During drain, exceed budget
                        for _ in 0..1000 {
                            cx.checkpoint()?;
                        }
                        Ok::<_, Error>(())
                    });

                    sub.sleep(Duration::from_millis(1)).await;
                    h.cancel();
                }).await;
            });
        }

        FinalizeBudgetExceeded => {
            runtime.block_on(async {
                let cx = runtime.root_cx();

                runtime.set_finalize_budget(Budget::new(1));

                cx.region(|sub| async move {
                    sub.register_finalizer(|| {
                        // Finalizer exceeds budget
                        for _ in 0..1000 {
                            std::hint::black_box(0);
                        }
                    });
                }).await;
            });
        }

        // =====================================================================
        // Race Mutations
        // =====================================================================

        AbandonLoser => {
            runtime.block_on(async {
                let cx = runtime.root_cx();

                cx.region(|sub| async move {
                    // Use mutated race that doesn't drain loser
                    runtime.set_mutation_abandon_loser(true);

                    let h1 = sub.spawn(async move |cx: Cx| {
                        cx.sleep(Duration::from_millis(10)).await;
                        1
                    });

                    let h2 = sub.spawn(async move |cx: Cx| {
                        cx.sleep(Duration::from_millis(100)).await;
                        2
                    });

                    // Race - h1 wins, h2 should be drained but isn't
                    let _ = cx.race(h1, h2).await;
                }).await;
            });
        }

        WrongWinner => {
            runtime.block_on(async {
                let cx = runtime.root_cx();

                runtime.set_mutation_wrong_winner(true);

                cx.region(|sub| async move {
                    let h1 = sub.spawn(async move |_| 1);
                    let h2 = sub.spawn(async move |cx: Cx| {
                        cx.sleep(Duration::from_secs(10)).await;
                        2
                    });

                    // h1 should win, but mutation returns h2's result
                    let winner = cx.race(h1, h2).await;
                    assert_eq!(winner, 1); // Will fail if mutation active
                }).await;
            });
        }

        LoserContinues => {
            runtime.block_on(async {
                let cx = runtime.root_cx();

                runtime.set_mutation_loser_continues(true);

                let side_effect = Arc::new(AtomicBool::new(false));
                let se = side_effect.clone();

                cx.region(|sub| async move {
                    let h1 = sub.spawn(async move |_| 1);
                    let h2 = sub.spawn(async move |cx: Cx| {
                        cx.sleep(Duration::from_millis(100)).await;
                        se.store(true, Ordering::SeqCst); // Should never happen
                        2
                    });

                    let _ = cx.race(h1, h2).await;

                    // Wait to see if loser continues
                    cx.sleep(Duration::from_millis(200)).await;
                }).await;

                // Side effect should not have happened
                assert!(!side_effect.load(Ordering::SeqCst));
            });
        }

        // =====================================================================
        // Region Mutations
        // =====================================================================

        CloseWithActiveChildren => {
            runtime.block_on(async {
                let cx = runtime.root_cx();

                runtime.set_mutation_force_close(true);

                cx.region(|sub| async move {
                    let _h = sub.spawn(async move |cx: Cx| {
                        cx.sleep(Duration::from_secs(100)).await;
                        42
                    });

                    // Force close without waiting for children
                }).await;
            });
        }

        CloseWithObligations => {
            runtime.block_on(async {
                let cx = runtime.root_cx();

                cx.region(|sub| async move {
                    let (tx, _rx) = sub.channel::<i32>(1);
                    let _permit = tx.reserve(&cx).await.unwrap();
                    // Close with unrealized permit
                }).await;
            });
        }

        EscapeRegionLifetime => {
            runtime.block_on(async {
                let cx = runtime.root_cx();

                // Try to escape a channel outside its region
                let escaped = cx.region(|sub| async move {
                    let (tx, rx) = sub.channel::<i32>(1);
                    (tx, rx) // Escape!
                }).await;

                // Try to use escaped channel
                let _ = escaped.0.send(&cx, 42).await;
            });
        }

        UseAfterClose => {
            runtime.block_on(async {
                let cx = runtime.root_cx();

                let region_id = cx.region(|sub| async move {
                    sub.region_id()
                }).await;

                // Try to access the closed region
                runtime.inject_region_access_after_close(region_id);
            });
        }

        // =====================================================================
        // Determinism Mutations
        // =====================================================================

        UseNonDetHashMap => {
            runtime.block_on(async {
                // Use std HashMap instead of DetHashMap
                let mut map = std::collections::HashMap::new();
                for i in 0..100 {
                    map.insert(i, i);
                }
                // Iteration order is non-deterministic
                let keys: Vec<_> = map.keys().collect();
                runtime.record_nondeterministic_operation("HashMap iteration", &keys);
            });
        }

        UseWallTime => {
            runtime.block_on(async {
                let cx = runtime.root_cx();

                // Use real time instead of virtual time
                let real_now = std::time::Instant::now();
                let virtual_now = cx.now();

                runtime.record_nondeterministic_operation("wall time access", &real_now);
            });
        }

        UseAmbientRng => {
            runtime.block_on(async {
                // Use thread_rng instead of Cx entropy
                let random_value: u64 = rand::random();
                runtime.record_nondeterministic_operation("ambient RNG", &random_value);
            });
        }

        UseRealSleep => {
            runtime.block_on(async {
                let cx = runtime.root_cx();

                // Use real sleep instead of virtual
                std::thread::sleep(Duration::from_millis(1));
                runtime.record_nondeterministic_operation("real sleep", &());
            });
        }

        // =====================================================================
        // Finalizer Mutations
        // =====================================================================

        SkipFinalizer => {
            runtime.block_on(async {
                let cx = runtime.root_cx();
                let finalized = Arc::new(AtomicBool::new(false));
                let f = finalized.clone();

                runtime.set_mutation_skip_finalizers(true);

                cx.region(|sub| async move {
                    sub.register_finalizer(move || {
                        f.store(true, Ordering::SeqCst);
                    });
                }).await;

                assert!(!finalized.load(Ordering::SeqCst), "Finalizer was skipped");
            });
        }

        DoubleFinalizer => {
            runtime.block_on(async {
                let cx = runtime.root_cx();
                let count = Arc::new(AtomicUsize::new(0));
                let c = count.clone();

                runtime.set_mutation_double_finalize(true);

                cx.region(|sub| async move {
                    sub.register_finalizer(move || {
                        c.fetch_add(1, Ordering::SeqCst);
                    });
                }).await;

                let final_count = count.load(Ordering::SeqCst);
                assert_eq!(final_count, 2, "Finalizer ran {} times", final_count);
            });
        }

        FinalizerPanic => {
            runtime.block_on(async {
                let cx = runtime.root_cx();

                cx.region(|sub| async move {
                    sub.register_finalizer(|| {
                        panic!("Finalizer panic!");
                    });
                }).await;
            });
        }

        FinalizerTimeout => {
            runtime.block_on(async {
                let cx = runtime.root_cx();

                runtime.set_finalize_budget(Budget::new(10));

                cx.region(|sub| async move {
                    sub.register_finalizer(|| {
                        // Infinite loop in finalizer
                        loop {
                            std::hint::black_box(0);
                        }
                    });
                }).await;
            });
        }

        // =====================================================================
        // Ambient Authority Mutations
        // =====================================================================

        SpawnWithoutCapability => {
            runtime.block_on(async {
                // Try to spawn without proper Cx
                runtime.spawn_without_cx(async {
                    42
                });
            });
        }

        TimeWithoutCapability => {
            runtime.block_on(async {
                // Access time without going through Cx
                let _ = runtime.time_without_cx();
            });
        }

        IoWithoutCapability => {
            runtime.block_on(async {
                // Perform I/O without Cx
                let _ = runtime.io_without_cx();
            });
        }
    }
}

/// Run all mutation tests and return results
pub fn run_all_mutations(config: &MutationConfig) -> Vec<MutationResult> {
    Mutation::all()
        .into_iter()
        .map(|m| run_mutation_test(m, config))
        .collect()
}

/// Run mutation tests for a specific category
pub fn run_category(category: MutationCategory, config: &MutationConfig) -> Vec<MutationResult> {
    Mutation::by_category(category)
        .into_iter()
        .map(|m| run_mutation_test(m, config))
        .collect()
}
