### 3. Coverage Tracking
```rust
// src/lab/meta/coverage.rs

use super::mutation::{Mutation, Severity};
use crate::lab::oracle::Oracle;
use std::collections::{HashMap, HashSet};
use serde::{Serialize, Deserialize};

/// Coverage status for an invariant/oracle
#[derive(Debug, Clone, Serialize)]
pub enum CoverageStatus {
    /// No mutation tests exist
    Untested,

    /// Some mutations tested but not all scenarios
    PartiallyTested {
        mutations_tested: Vec<Mutation>,
        mutations_missing: Vec<Mutation>,
        coverage_percent: f64,
    },

    /// All known mutation scenarios tested
    FullyTested {
        mutations_tested: Vec<Mutation>,
    },
}

/// Oracle coverage report
#[derive(Debug, Serialize)]
pub struct OracleCoverage {
    pub oracle: Oracle,
    pub status: CoverageStatus,
    pub mutation_results: HashMap<Mutation, bool>,
    pub kill_rate: f64, // Percentage of mutations caught
}

/// Complete coverage report
#[derive(Debug, Serialize)]
pub struct CoverageReport {
    pub oracles: Vec<OracleCoverage>,
    pub total_mutations: usize,
    pub mutations_passed: usize,
    pub mutations_failed: usize,
    pub overall_coverage: f64,
    pub kill_rate: f64,
    pub by_severity: HashMap<Severity, SeverityStats>,
    pub uncaught_critical: Vec<Mutation>,
    pub timestamp: chrono::DateTime<chrono::Utc>,
}

#[derive(Debug, Serialize)]
pub struct SeverityStats {
    pub total: usize,
    pub caught: usize,
    pub kill_rate: f64,
}

impl CoverageReport {
    /// Compute coverage from mutation test results
    pub fn compute(results: &[MutationResult]) -> Self {
        let mut oracle_mutations: HashMap<Oracle, Vec<(Mutation, bool)>> = HashMap::new();
        let mut by_severity: HashMap<Severity, (usize, usize)> = HashMap::new();
        let mut uncaught_critical = Vec::new();

        for result in results {
            // Track by oracle
            for oracle in &result.expected_oracles {
                oracle_mutations
                    .entry(*oracle)
                    .or_default()
                    .push((result.mutation, result.passed));
            }

            // Track by severity
            let severity = result.mutation.severity();
            let entry = by_severity.entry(severity).or_insert((0, 0));
            entry.0 += 1;
            if result.passed {
                entry.1 += 1;
            } else if severity == Severity::Critical {
                uncaught_critical.push(result.mutation);
            }
        }

        let oracles: Vec<OracleCoverage> = Oracle::all().iter().map(|&oracle| {
            let mutations = oracle_mutations.get(&oracle).cloned().unwrap_or_default();
            let mutation_results: HashMap<Mutation, bool> = mutations.iter().cloned().collect();

            let (tested, failed): (Vec<_>, Vec<_>) = mutations.iter()
                .partition(|(_, passed)| *passed);

            let kill_rate = if mutations.is_empty() { 
                0.0 
            } else { 
                tested.len() as f64 / mutations.len() as f64 
            };

            let status = if mutations.is_empty() {
                CoverageStatus::Untested
            } else if failed.is_empty() {
                CoverageStatus::FullyTested {
                    mutations_tested: tested.iter().map(|(m, _)| *m).collect(),
                }
            } else {
                CoverageStatus::PartiallyTested {
                    mutations_tested: tested.iter().map(|(m, _)| *m).collect(),
                    mutations_missing: failed.iter().map(|(m, _)| *m).collect(),
                    coverage_percent: kill_rate * 100.0,
                }
            };

            OracleCoverage { oracle, status, mutation_results, kill_rate }
        }).collect();

        let total = results.len();
        let passed = results.iter().filter(|r| r.passed).count();

        let severity_stats: HashMap<Severity, SeverityStats> = by_severity.into_iter()
            .map(|(sev, (total, caught))| {
                (sev, SeverityStats {
                    total,
                    caught,
                    kill_rate: if total > 0 { caught as f64 / total as f64 } else { 0.0 },
                })
            })
            .collect();

        CoverageReport {
            oracles,
            total_mutations: total,
            mutations_passed: passed,
            mutations_failed: total - passed,
            overall_coverage: if total > 0 { passed as f64 / total as f64 } else { 0.0 },
            kill_rate: if total > 0 { passed as f64 / total as f64 } else { 0.0 },
            by_severity: severity_stats,
            uncaught_critical,
            timestamp: chrono::Utc::now(),
        }
    }

    /// Generate human-readable report
    pub fn to_string_report(&self) -> String {
        let mut out = String::new();

        out.push_str(&format!("# Mutation Testing Coverage Report\n"));
        out.push_str(&format!("Generated: {}\n\n", self.timestamp));

        out.push_str(&format!("## Summary\n"));
        out.push_str(&format!("- Total mutations: {}\n", self.total_mutations));
        out.push_str(&format!("- Passed (caught): {}\n", self.mutations_passed));
        out.push_str(&format!("- Failed (escaped): {}\n", self.mutations_failed));
        out.push_str(&format!("- Kill rate: {:.1}%\n\n", self.kill_rate * 100.0));

        if !self.uncaught_critical.is_empty() {
            out.push_str("## ⚠️  CRITICAL MUTATIONS NOT CAUGHT\n");
            for m in &self.uncaught_critical {
                out.push_str(&format!("- {:?}: {}\n", m, m.description()));
            }
            out.push_str("\n");
        }

        out.push_str("## By Severity\n");
        for sev in [Severity::Critical, Severity::High, Severity::Medium, Severity::Low] {
            if let Some(stats) = self.by_severity.get(&sev) {
                out.push_str(&format!(
                    "- {:?}: {}/{} ({:.1}%)\n",
                    sev, stats.caught, stats.total, stats.kill_rate * 100.0
                ));
            }
        }
        out.push_str("\n");

        out.push_str("## By Oracle\n");
        for oc in &self.oracles {
            let status_str = match &oc.status {
                CoverageStatus::Untested => "❌ Untested".to_string(),
                CoverageStatus::PartiallyTested { coverage_percent, .. } => {
                    format!("⚠️  Partial ({:.0}%)", coverage_percent)
                }
                CoverageStatus::FullyTested { .. } => "✓ Full".to_string(),
            };
            out.push_str(&format!("- {:?}: {} (kill rate: {:.0}%)\n", 
                oc.oracle, status_str, oc.kill_rate * 100.0));
        }

        out
    }

    /// Export to JSON
    pub fn to_json(&self) -> String {
        serde_json::to_string_pretty(self).unwrap_or_default()
    }
}
