### 4. Chaos Testing Mode
```rust
// src/lab/meta/chaos.rs

use crate::lab::{LabRuntime, LabConfig};
use crate::util::DetRng;
use std::time::Duration;

/// Chaos testing configuration
#[derive(Clone)]
pub struct ChaosConfig {
    /// Random seed for reproducibility
    pub seed: u64,

    /// Probability of injecting a fault (0.0 - 1.0)
    pub fault_probability: f64,

    /// Types of faults to inject
    pub enabled_faults: Vec<ChaosFault>,

    /// Maximum duration for chaos run
    pub max_duration: Duration,

    /// Stop on first failure
    pub fail_fast: bool,

    /// Detailed logging
    pub verbose: bool,
}

impl Default for ChaosConfig {
    fn default() -> Self {
        Self {
            seed: 0xCHAOS_SEED,
            fault_probability: 0.1,
            enabled_faults: ChaosFault::all(),
            max_duration: Duration::from_secs(60),
            fail_fast: false,
            verbose: false,
        }
    }
}

/// Types of chaos faults that can be injected
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum ChaosFault {
    /// Delay task execution
    TaskDelay,

    /// Cancel random tasks
    RandomCancel,

    /// Reorder task scheduling
    ScheduleReorder,

    /// Inject memory pressure
    MemoryPressure,

    /// Simulate slow I/O
    SlowIo,

    /// Drop messages
    MessageDrop,

    /// Corrupt messages (bit flip)
    MessageCorrupt,

    /// Partition network
    NetworkPartition,

    /// Task timeout
    TaskTimeout,
}

impl ChaosFault {
    pub fn all() -> Vec<Self> {
        use ChaosFault::*;
        vec![
            TaskDelay, RandomCancel, ScheduleReorder, MemoryPressure,
            SlowIo, MessageDrop, MessageCorrupt, NetworkPartition, TaskTimeout,
        ]
    }
}

/// Chaos runtime wrapper that injects faults
pub struct ChaosRuntime {
    inner: LabRuntime,
    config: ChaosConfig,
    rng: DetRng,
    faults_injected: Vec<InjectedFault>,
}

#[derive(Debug, Clone)]
pub struct InjectedFault {
    pub fault: ChaosFault,
    pub timestamp: crate::types::Time,
    pub target: String,
    pub details: String,
}

impl ChaosRuntime {
    pub fn new(config: ChaosConfig) -> Self {
        let lab_config = LabConfig {
            entropy_seed: config.seed,
            ..Default::default()
        };

        Self {
            inner: LabRuntime::with_config(lab_config),
            rng: DetRng::new(config.seed),
            config,
            faults_injected: Vec::new(),
        }
    }

    /// Maybe inject a fault based on probability
    pub fn maybe_inject(&mut self) -> Option<InjectedFault> {
        if self.rng.next_f64() > self.config.fault_probability {
            return None;
        }

        let fault_idx = self.rng.next_usize(self.config.enabled_faults.len());
        let fault = self.config.enabled_faults[fault_idx];

        let injected = self.inject_fault(fault);
        self.faults_injected.push(injected.clone());

        if self.config.verbose {
            tracing::info!(fault = ?injected, "Chaos fault injected");
        }

        Some(injected)
    }

    fn inject_fault(&mut self, fault: ChaosFault) -> InjectedFault {
        use ChaosFault::*;

        let timestamp = self.inner.virtual_now();

        let (target, details) = match fault {
            TaskDelay => {
                let delay_ms = self.rng.next_usize(100) + 1;
                self.inner.inject_delay(Duration::from_millis(delay_ms as u64));
                ("scheduler".into(), format!("delay {}ms", delay_ms))
            }

            RandomCancel => {
                if let Some(task_id) = self.inner.random_active_task(&mut self.rng) {
                    self.inner.inject_cancel(task_id);
                    (format!("task:{}", task_id), "cancelled".into())
                } else {
                    ("none".into(), "no active tasks".into())
                }
            }

            ScheduleReorder => {
                self.inner.shuffle_ready_queue(&mut self.rng);
                ("scheduler".into(), "reordered ready queue".into())
            }

            MemoryPressure => {
                let alloc_size = self.rng.next_usize(1024 * 1024) + 1024;
                self.inner.inject_memory_pressure(alloc_size);
                ("memory".into(), format!("allocated {} bytes", alloc_size))
            }

            SlowIo => {
                let delay_ms = self.rng.next_usize(500) + 100;
                self.inner.inject_io_delay(Duration::from_millis(delay_ms as u64));
                ("io".into(), format!("delay {}ms", delay_ms))
            }

            MessageDrop => {
                self.inner.inject_message_drop();
                ("network".into(), "dropped next message".into())
            }

            MessageCorrupt => {
                self.inner.inject_message_corrupt();
                ("network".into(), "corrupted next message".into())
            }

            NetworkPartition => {
                let duration_ms = self.rng.next_usize(1000) + 100;
                self.inner.inject_partition(Duration::from_millis(duration_ms as u64));
                ("network".into(), format!("partition for {}ms", duration_ms))
            }

            TaskTimeout => {
                if let Some(task_id) = self.inner.random_active_task(&mut self.rng) {
                    self.inner.inject_timeout(task_id);
                    (format!("task:{}", task_id), "timeout".into())
                } else {
                    ("none".into(), "no active tasks".into())
                }
            }
        };

        InjectedFault { fault, timestamp, target, details }
    }

    /// Run with chaos injection
    pub fn run_with_chaos<F, T>(&mut self, f: F) -> ChaosResult<T>
    where
        F: FnOnce(&mut LabRuntime) -> T,
    {
        let start = std::time::Instant::now();

        // Install chaos hooks
        self.inner.install_chaos_hook(|rt| {
            // This closure is called periodically
            // In a real impl, self.maybe_inject() would be called here
        });

        let result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
            f(&mut self.inner)
        }));

        let elapsed = start.elapsed();

        ChaosResult {
            result: result.ok(),
            panicked: result.is_err(),
            faults_injected: self.faults_injected.clone(),
            violations: self.inner.violations().to_vec(),
            elapsed,
        }
    }

    /// Get injected faults
    pub fn faults(&self) -> &[InjectedFault] {
        &self.faults_injected
    }
}

/// Result of a chaos test run
#[derive(Debug)]
pub struct ChaosResult<T> {
    pub result: Option<T>,
    pub panicked: bool,
    pub faults_injected: Vec<InjectedFault>,
    pub violations: Vec<Violation>,
    pub elapsed: Duration,
}

impl<T> ChaosResult<T> {
    pub fn succeeded(&self) -> bool {
        self.result.is_some() && !self.panicked && self.violations.is_empty()
    }
}

/// Run chaos tests with different seeds
pub fn chaos_sweep(
    seeds: impl Iterator<Item = u64>,
    config_template: ChaosConfig,
    test_fn: impl Fn(&mut ChaosRuntime),
) -> Vec<ChaosResult<()>> {
    seeds.map(|seed| {
        let config = ChaosConfig { seed, ..config_template.clone() };
        let mut runtime = ChaosRuntime::new(config);
        runtime.run_with_chaos(|rt| {
            test_fn(&mut ChaosRuntime { 
                inner: std::mem::replace(rt, LabRuntime::new()),
                config: config_template.clone(),
                rng: DetRng::new(seed),
                faults_injected: Vec::new(),
            });
        })
    }).collect()
}
